package com.chaobo.scm.supplier.domain.profile;import com.chaobo.scm.common.error.BusinessException;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.junit.jupiter.api.Test;import java.util.concurrent.atomic.AtomicLong;import static org.assertj.core.api.Assertions.*;
class SupplierAdmissionAggregateTest{private final Ids ids=new Ids();private SupplierAdmissionAggregate admission(){return SupplierAdmissionAggregate.create("SUP-C1","候选供应商","91310000","MANUFACTURER","张三","13800000000","{\"taxNo\":\"91310000\"}",1,ids);}@Test void shouldSubmitAndApprove(){var a=admission();a.submit(1,ids);a.approve(2,ids);assertThat(a.status()).isEqualTo(SupplierAdmissionStatus.APPROVED);assertThat(a.pullEvents()).hasSize(3);}@Test void shouldNotApprovePotentialSupplier(){assertThatThrownBy(()->admission().approve(2,ids)).isInstanceOf(BusinessException.class);}private static class Ids implements IdentifierGenerator{private final AtomicLong n=new AtomicLong(1);public long nextId(){return n.getAndIncrement();}public String nextBusinessNo(String p){return p+n.getAndIncrement();}}}
